const BASE_URL = "http://localhost:5000/api";

/* AUTH */
export const signup = async (data) => {
  const res = await fetch(`${BASE_URL}/auth/signup`, {
    method: "POST",
    headers: {"Content-Type": "application/json"},
    body: JSON.stringify(data),
  });
  return res.json();
};

export const login = async (data) => {
  const res = await fetch(`${BASE_URL}/auth/login`, {
    method: "POST",
    headers: {"Content-Type": "application/json"},
    body: JSON.stringify(data),
  });
  return res.json();
};

/* SCORES */
export const getScores = async (token) => {
  const res = await fetch(`${BASE_URL}/scores`, {
    headers: { Authorization: token },
  });
  return res.json();
};

export const addScore = async (score, token) => {
  await fetch(`${BASE_URL}/scores/add`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: token,
    },
    body: JSON.stringify({ score }),
  });
};

/* CHARITY */
export const getCharities = async () => {
  const res = await fetch(`${BASE_URL}/charity`);
  return res.json();
};

export const selectCharity = async (charity, token) => {
  await fetch(`${BASE_URL}/charity/select`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: token,
    },
    body: JSON.stringify({ charity }),
  });
};

/* DRAW */
export const runDraw = async (token) => {
  const res = await fetch(`${BASE_URL}/draw/run`, {
    headers: { Authorization: token },
  });
  return res.json();
};
